import React, { useState } from "react";
import styled from "styled-components";
import { Spinner } from "./form-sections";
import { media } from "./media-queries";
import { SubmitButton } from "../components/ButtonLink";
import { LabeledInput } from "../components/LabeledInput";
import { LabeledTextarea } from "../components/LabeledTextarea";
import { FormElementsColumnWrapper } from "../helpers/form-sections";

/*
        action="https://europe-west1-vosbor-io.cloudfunctions.net/function-vosbor-form-mailer"
        method="POST"
        autoComplete="off"
        enctype="multipart/form-data"
*/

export const ContactForm = ({ type }) => {
  const [name, setName] = useState(null);
  const [company, setCompany] = useState(null);
  const [email, setEmail] = useState(null);
  const [message, setMessage] = useState(null);

  const [loading, setLoading] = useState(false);

  const onFormSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const url =
      "https://europe-west1-vosbor-io.cloudfunctions.net/function-vosbor-form-mailer";
    const formData = new FormData();
    formData.append("type", type);
    formData.append("name", name);
    formData.append("company", company);
    formData.append("email", email);
    formData.append("message", message);
    const config = {
      method: "POST",
      mode: "cors",
      cache: "no-cache",
      body: formData,
    };

    try {
      const response = await fetch(url, config);

      console.log(response.data);
      window.location = "/response-ok";
    } catch (error) {
      console.log("ERROR:", error);
      setLoading(false);
    }
  };

  return (
    <FormWrapper>
      {loading && <Spinner />}
      <Form onSubmit={onFormSubmit}>
        <input type="hidden" name="type" value={type} />
        <FormElementsColumnWrapper>
          <LabeledInput
            type="text"
            placeholder="Enter full name"
            name="name"
            autoComplete="off"
            onChange={(e) => setName(e?.target?.value)}
            disabled={loading ? "disabled" : ""}
            label="Full name"
            required
          />
          <LabeledInput
            type="text"
            placeholder="Enter company name"
            name="company"
            autoComplete="off"
            onChange={(e) => setCompany(e?.target?.value)}
            disabled={loading ? "disabled" : ""}
            label="Company"
          />
        </FormElementsColumnWrapper>
        <LabeledInput
          type="email"
          placeholder="Enter email address"
          name="email"
          autoComplete="off"
          onChange={(e) => setEmail(e?.target?.value)}
          disabled={loading ? "disabled" : ""}
          required
          label="Email address"
        />
        <LabeledTextarea
          placeholder="Type message..."
          name="message"
          autoComplete="off"
          onChange={(e) => setMessage(e?.target?.value)}
          disabled={loading ? "disabled" : ""}
          label="Message"
          required
        />
        <InfoText>
          Your data will only be used by authorised Vosbor personnel, not
          distributed to third parties and only used to contact you and to send
          you our newsletter. By using the contact form you agree to our privacy
          policy.
        </InfoText>
        <StyledSubmitButton $thin disabled={loading ? "disabled" : ""}>
          Submit
        </StyledSubmitButton>
      </Form>
    </FormWrapper>
  );
};

const FormWrapper = styled.div`
  ${media.m`
    display: flex;
    flex-direction: column;
    align-items: center;
  `}
`;

const Form = styled.form`
  display: flex;
  flex-direction: column;
  align-items: stretch;
  gap: 32px;

  ${media.m`
    max-width: 560px;
    width: 100%;
  `}
`;

const InfoText = styled.span`
  margin-top: -16px;
  font-family: "Roboto";
  font-style: normal;
  font-weight: 400;
  font-size: 9px;
  line-height: 18px;
  text-align: right;
  letter-spacing: 0.002em;
  color: #747487;
`;

const StyledSubmitButton = styled(SubmitButton)`
  margin-top: 24px;
  width: 100%;

  ${media.m`
    width: 160px;
  `}
`;
